fun solve(edges: Array<Array<Long>>, online: Array<Boolean>, k: Long): Long {
    val n = online.size
    val adj = Array(n) { mutableListOf<Pair<Long, Long>>() }
    for (edge in edges) {
        val u = edge[0]
        val v = edge[1]
        val cost = edge[2]
        adj[u].add(Pair(v, cost))
    }

    val bestMin = LongArray(n) { -Long.MAX_VALUE }
    val pq = PriorityQueue<Triple<Long, Long, Long>> { a, b ->
        if (a.first != b.first) {
            return@PriorityQueue a.first < b.first
        }
        return@PriorityQueue 0
    }

    for (edge in adj[0]) {
        val v = edge.first
        val cost = edge.second
        if (online[v] && cost <= k) {
            bestMin[v] = cost
            pq.add(Triple(-cost, cost, v))
        }
    }

    while (pq.isNotEmpty()) {
        val (negCurrentMin, currentTotal, u) = pq.poll()
        val currentMin = -negCurrentMin

        if (u == n - 1L) {
            return currentMin
        }

        if (currentTotal > k) continue
        if (currentMin < bestMin[u]) continue

        for (edge in adj[u]) {
            val v = edge.first
            val cost = edge.second
            if (!online[v]) continue

            val newTotal = currentTotal + cost
            if (newTotal > k) continue

            val newMin = min(currentMin, cost)
            if (newMin > bestMin[v]) {
                bestMin[v] = newMin
                pq.add(Triple(-newMin, newTotal, v))
            }
        }
    }

    return -1
}
